var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"관리부장님. 부탁하셨던 일정 산출이 끝났습니다.","JPN":"管理部長様、申し付けられていた日程の算出が終わりました。","ENG":"Manager, I've completed drafting the schedule per your request.","TWN":"管理部長，您委託的日程算出來了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"청소만큼 일정도 무척 깔끔하게 정리해 주셨네요. 바쁠 텐데 고마워요.","JPN":"掃除も日程も、とても綺麗に整理してくれましたね。忙しいのにありがとうございます。","ENG":"This is as immaculate as your cleaning work. Thank you for this. I'm sure you're busy with other things.","TWN":"做得很好，謝謝妳了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"별말씀을요. 주인님의 사업에 이바지할 수 있게 되어 영광입니다.","JPN":"とんでもございません。ご主人様の事業に貢献できて光栄です。","ENG":"You're most welcome. It's my honor to contribute to the Master's business.","TWN":"不會，能幫到主人，我感到無限光榮。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그리고 주인님께 드릴 커피를 내렸습니다만, 관리부장님께서도 어떠신가요?","JPN":"ご主人様に差し上げるコーヒーを淹れたのですが、管理部長様もいかがでしょうか。","ENG":"I've also brewed some coffee for the Master. Would you care for a cup yourself?","TWN":"對了，我幫主人沖了杯現磨咖啡，您要喝點嗎？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그럼 한 잔 부탁드릴게요. 저번에 입수하셨다던 좋은 원두가 어떤 맛일지 궁금하네요.","JPN":"それでは、お言葉に甘えて。この前入手したコーヒー豆の味が気になりますね。","ENG":"Yes, please. I can't wait to taste the good beans you got the other day.","TWN":"那也給我來一杯吧，聽說老闆上次入手了不錯的咖啡豆，也不知道味道如何。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"네. 시중에서는 구하기 어려운 물건이니 모쪼록 기대해 주시길.","JPN":"はい。通常のお店では手に入らないものですので、どうか楽しみにしてください。","ENG":"It's hard to find on the market. I'm sure you'll enjoy it.","TWN":"好的，那是在市面上不容易買到的，敬請期待吧。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"......나도 커피 잘 탈 수 있는데.","JPN":"……私だって美味しいコーヒーを淹れられるのに。","ENG":"I can make a mean cup of coffee, too.","TWN":"……我沖的咖啡也很好喝。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"동경하던 관리부장 옆자리를 처음 보는 사람이 가로채서 분한가요?","JPN":"憧れの管理部長の一番弟子の座を横取りされて悔しいんですか？","ENG":"Are you upset because some stranger won over your admired Manager's heart instead?","TWN":"妳崇拜的管理部長，就這麼被剛來的人搶走了，是不是覺得很氣憤？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"그런 레나 양에게 딱 맞는 특제 부적이 마침 할인가로 나와 있습니다.","JPN":"そんなレナにピッタリな特製お守りを割引価格で提供できますよ。","ENG":"I've got just the talisman for you. And it's on sale, too.","TWN":"這裡有一個非常適合蕾娜的特製護身符在打折哦。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"......효과 확실해?","JPN":"……効果は確かなの？","ENG":"You sure it will work?","TWN":"……效果如何？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"레나님! 이것 좀 보십셔!","JPN":"レナ様！　これを見てほしいっす！","ENG":"Ms. Lena! Look at this!","TWN":"蕾娜小姐！妳看看這個！"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"브리핑 룸 구석에서 찾은 맥주 박스임다! 이거면 배터지게 마실 수 있을 검다!","JPN":"会議室の隅で見つけたビールのケースっす！　こんだけあるならみんなでお腹がいっぱいになるまで飲めそうっす！","ENG":"I found a six pack in the corner of the briefing room! It's enough for you to drink all night!","TWN":"這個是我在簡報室角落找到的啤酒箱子！這些可以喝到撐了！"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"앗?! 모네 너, 그 맥주 어디서 가져 온 거야?!","JPN":"えっ！？　モネ、そのビールどこから持ってきたの！？","ENG":"Huh?! Mone, where did you find that beer?!","TWN":"額？！莫妮，那啤酒是從哪裡來的？！"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"레나 양...... 설마 회사에선 마시지 말라고 그렇게 말했는데 또......","JPN":"レナさん……会社では飲まないようにとあれだけ言ったのにまた……","ENG":"Lena... I told you not to drink on duty... yet here you are again...","TWN":"蕾娜……我說過多少次不要在公司裡喝酒，妳又……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"관리부장님! 그게, 그게 말이죠!","JPN":"管理部長！　いや、違います！","ENG":"Manager! I-it's not what it looks like!","TWN":"管理部長！那、那是因為！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"모네 너, 나중에 두고 봐!","JPN":"モネ！　あとで話があるからね！","ENG":"You'll pay for this, Mone!","TWN":"莫妮，妳給我等著瞧！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};